const input = $input.first()?.json || {};

function flagEnabled(value, fallback = true) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

const setBase = {
  Company: input.Company || input.company || 'TecnoComp',
  company: input.company || input.Company || 'TecnoComp',
  timezone: input.timezone || 'America/Santiago',
  email_from: input.email_from || 'notificaciones@dominio.cl',
  email_to: input.email_to || 'destinatario@dominio.cl',
  email_cc: input.email_cc || '',
  email_bcc: input.email_bcc || '',
  itop_url: input.itop_url || 'http://172.16.123.132/itop/',
  itop_organization: input.itop_organization || 'Minera GoldFields Chile',
  itop_limit: Number(input.itop_limit || 5000),
  template_root: input.template_root || '/opt/n8n-config/templates/mail/v1',
  source_label: input.source_label || input.report_source_label || 'Producci\u00f3n / iTop CMDB',
  default_detail_level: input.default_detail_level || 'full',
  flags: {
    send_email: flagEnabled(input.send_email, true),
    include_attachment: flagEnabled(input.include_attachment, true),
    include_summary: flagEnabled(input.include_summary, true),
    include_detail: flagEnabled(input.include_detail, true),
    include_operational_notes: flagEnabled(input.include_operational_notes, true),
    include_itop_button_footer: flagEnabled(input.include_itop_button_footer, true),
    include_requirements: flagEnabled(input.include_requirements, true),
    include_incidents: flagEnabled(input.include_incidents, true),
    include_changes: flagEnabled(input.include_changes, true),
    include_problems: flagEnabled(input.include_problems, true),
  },
};

return [{ json: { ...setBase, set_base_version: 'mail-config-v3' } }];
